optimized_federated_query:
# Smart Federated Query with Class Constraints
# Note: Multiple class interpretations exist but all route to same endpoints
# A single query retrieves all data regardless of class ambiguity

SELECT ?actor ?movie ?movieTitle ?movieDate ?birthDate ?spouseName ?actor_name_en ?spouseURI ?imdbactor ?actor_name.
WHERE {

  SERVICE <http://localhost:8891/sparql/> {
    ?actor <http://dbpedia.org/ontology/spouse> ?spouseURI . # ?actor:Model, ?spouseURI:Actor
    ?actor <http://www.w3.org/2000/01/rdf-schema#label> ?actor_name_en . # ?actor:MixedMartialArtsLeague, ?actor_name_en:Literal
    ?spouseURI <http://www.w3.org/2000/01/rdf-schema#label> ?spouseName . # ?spouseURI:MixedMartialArtsLeague, ?spouseName:Literal
    ?actor <http://dbpedia.org/ontology/birthDate> ?birthDate . # ?actor:GaelicGamesPlayer, ?birthDate:Literal
  }

  SERVICE <http://localhost:8896/sparql/> {
    ?movie <http://purl.org/dc/terms/title> ?movieTitle . # ?movie:film, ?movieTitle:Literal
    ?imdbactor <http://data.linkedmdb.org/resource/movie/actor_name> ?actor_name . # ?imdbactor:Person, ?actor_name:Literal
    ?movie <http://purl.org/dc/terms/date> ?movieDate . # ?movie:film, ?movieDate:Literal
    ?movie <http://data.linkedmdb.org/resource/movie/actor> ?imdbactor . # ?movie:film, ?imdbactor:Person
  }
}
LIMIT 1000
